polling_after_3ds.code:
async function pollAfter3DS(paymentId) {
  for (let i = 0; i < 36; i++) {  // max 3 min at 5s intervals
    await sleep(5000);
    const res = await callMerchantMCP('get_checkout', { payment_id: paymentId });
    if (res.status === 'captured') return { success: true };
    if (res.status === 'failed') return { success: false, reason: res.error_code };
  }
  return { success: false, reason: 'timeout' };
}
